+        Self::Spiral,
+        Self::SpinLattice,
+    ];
+
+    fn next(self) -> Self {
+        let idx = Self::ALL.iter().position(|&e| e == self).unwrap_or(0);
+        Self::ALL[(idx + 1) % Self::ALL.len()]
+    }
+
+    fn prev(self) -> Self {
+        let idx = Self::ALL.iter().position(|&e| e == self).unwrap_or(0);
+        Self::ALL[(idx + Self::ALL.len() - 1) % Self::ALL.len()]
+    }
